const data = $input.first().json.data;
if (!data || !data.items) return [];
const wormwood = data.items.filter(function(item) {
  if (!item.status) return true;
  if (item.status !== 'Backlog') return false;
  var nonStatus = (item.meta && item.meta.field_changes || []).filter(function(fc) { return fc.field !== 'Status'; });
  return nonStatus.length === 0;
});
if (wormwood.length === 0) return [];
return [{ json: {
  payload: JSON.stringify({ items: wormwood, project_fields: data.project_fields }),
  claudeToken: $env.CLAUDE_CODE_OAUTH_TOKEN || '',
  ghToken: $env.GH_TOKEN || ''
} }];

var stdout = $input.first().json.stdout;
if (stdout && stdout.trim() === 'busy') return [];
var gate = $('Gate: Wormwood').first().json;
return [{ json: gate }];

const data = $input.first().json.data;
if (!data || !data.items) return [];
var tracer = data.items.filter(function(i) { return i.status === 'In Review'; });
if (tracer.length === 0) return [];
return [{ json: {
  payload: JSON.stringify({ items: tracer, project_fields: data.project_fields }),
  claudeToken: $env.CLAUDE_CODE_OAUTH_TOKEN || '',
  ghToken: $env.GH_TOKEN || ''
} }];

var stdout = $input.first().json.stdout;
if (stdout && stdout.trim() === 'busy') return [];
var gate = $('Gate: Tracer').first().json;
return [{ json: gate }];

const data = $input.first().json.data;
if (!data || !data.items) return [];
var actionable = data.items.filter(function(i) { return i.status === 'In Progress' || i.status === 'Ready'; });
if (actionable.length === 0) return [];
actionable.sort(function(a, b) {
  if (a.status === 'In Progress' && b.status !== 'In Progress') return -1;
  if (b.status === 'In Progress' && a.status !== 'In Progress') return 1;
  return 0;
});
return [{ json: {
  payload: JSON.stringify({ item: actionable[0], project_fields: data.project_fields }),
  claudeToken: $env.CLAUDE_CODE_OAUTH_TOKEN || '',
  ghToken: $env.GH_TOKEN || ''
} }];

var stdout = $input.first().json.stdout;
if (stdout && stdout.trim() === 'busy') return [];
var gate = $('Gate: Moe').first().json;
return [{ json: gate }];
